mapper.select:
SELECT sensor_id AS sensorId, device_no AS deviceNo, file_name AS fileName, file_path AS filePath,
       file_size AS fileSize, sample_rate AS sampleRate, channel_count AS channelCount,
       point_count AS pointCount, duration_seconds AS durationSeconds, collect_time AS collectTime
FROM vibration_dat_data
WHERE sensor_id = #{sensorId} AND deleted = 0
AND collect_time >= #{startTime}
AND collect_time <= #{endTime}
ORDER BY collect_time ASC
LIMIT #{limit}
